import sys
import random


def random_string(length):
    return "".join(
        random.choice("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789")
        for _ in range(length)
    )


def random_bytes(length):
    return bytes(random.randint(0, 255) for _ in range(length))


